insert into bank_questions (question_key, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('2-4-2-product-and-product-life:match:9eea5cfa', '2-4-2-product-and-product-life', '2.4.2 Product & Product Life Cycle', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Extension Strategy”?", "options": ["When a business comes up with a completely new product or service from scratch.", "Methods used (like price drops or new packaging) to keep sales high during the maturity stage.", "When a business improves a product which already exists (e.g. adding Bluetooth to a toothbrush).", "When a business plans what a product will do (function) and what it will look like (style)."]}'::jsonb, '{"answer": 1, "explain": "“Extension Strategy” means: Methods used (like price drops or new packaging) to keep sales high during the maturity stage."}'::jsonb),
('2-4-3-pricing-methods:mcq:ef1be0fe', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'mcq', 'mcq', 1, '{"question": "Price skimming is best defined as:", "options": ["charging a lower price when a product becomes old", "keeping the price of a product the same as competitors", "making sure your price is always more than competitors permanently", "setting a higher price when a product is new and has an advantage over competitors"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: D. Skimming sets a high initial price for a new, highly desired or technical product, lowering it later when competitors enter."}'::jsonb),
('2-4-3-pricing-methods:mcq:c4c2c117', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'mcq', 'mcq', 1, '{"question": "Penetration pricing would normally be used when:", "options": ["a business has been in operation some time and has few competitors", "a product is being introduced which is at the cutting edge of technology", "a business is new and needs to establish its place in a crowded market", "there is incredibly high demand for a luxury product"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. Penetration pricing involves setting prices below competitors to ''break into'' a crowded market and steal market share quickly."}'::jsonb),
('2-4-3-pricing-methods:mcq:b33ef750', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'mcq', 'mcq', 1, '{"question": "If a business wishes to dispose of old stock to make way for new products, it would normally consider:", "options": ["Competitor pricing", "Promotional pricing", "Cost-plus pricing", "Skimming"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Promotional pricing (like a store sale) reduces prices for a short period specifically to clear old stock or give a quick boost to sales."}'::jsonb),
('2-4-3-pricing-methods:mcq:aa6c4327', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'mcq', 'mcq', 1, '{"question": "A business is likely to use cost-plus pricing when it:", "options": ["has surplus stock to sell off quickly", "sees that a number of competitors are starting to have an effect on sales", "feels that it must guarantee a set amount of profit is made on every unit sold", "is a new business and has to make sure it has an advantage over competitors"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. Cost-plus pricing calculates the exact cost to make the item and adds a specific percentage mark-up, guaranteeing that a profit is made on each sale."}'::jsonb),
('2-4-3-pricing-methods:mcq:2d285bd4', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'mcq', 'mcq', 1, '{"question": "A hairdresser charges the exact same price for haircuts as two other hairdressers in the local area. Which pricing method is this?", "options": ["Competitor pricing", "Cost-plus pricing", "Penetration pricing", "Promotional pricing"]}'::jsonb, '{"answer": 0, "explain": "Correct answer: A. By setting prices identically to local rivals, the business is using competitor pricing."}'::jsonb),
('2-4-3-pricing-methods:mcq:cd535b89', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'mcq', 'mcq', 1, '{"question": "A fast-food restaurant is currently charging 60p for its new healthy snack. It intends to increase the price to £2.25 once the snack has become popular. This is an example of:", "options": ["Competitor pricing", "Cost-plus pricing", "Penetration pricing", "Price skimming"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. Starting with an artificially low price to gain popularity and market share, with the intent to raise it later, is the exact definition of penetration pricing."}'::jsonb),
('2-4-3-pricing-methods:mcq:645c7c78', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'mcq', 'mcq', 1, '{"question": "A store buys frozen oven chips for 29p a pack. The store usually sells them for 99p. If it wishes to use them as a ''loss leader'', how much should it charge?", "options": ["29p a pack", "Between 29p and 99p a pack", "Less than 29p a pack", "More than 99p a pack"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. A loss leader must be sold at a price lower than the cost it took the business to acquire or make it. Since the cost was 29p, a loss leader price must be less than 29p."}'::jsonb),
('2-4-3-pricing-methods:mcq:e033a526', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'mcq', 'mcq', 1, '{"question": "Which of the following is a major disadvantage of Competitor Pricing?", "options": ["It guarantees a profit on every item sold.", "It results in massive cash flow problems immediately.", "The business must find other, non-price ways to attract customers.", "It makes the product look too cheap and damages brand image."]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. Because the price is identical to rivals, the business loses price as a competitive advantage and must compete on quality, service, or advertising instead."}'::jsonb),
('2-4-3-pricing-methods:mcq:83b04486', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'mcq', 'mcq', 1, '{"question": "Apple introduces its latest iPhone. What pricing strategy are they most likely to use?", "options": ["Penetration pricing", "Price Skimming", "Cost-plus pricing", "Promotional pricing"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Apple uses price skimming. Consumers want to be up-to-date with the latest technology and are willing to pay a very high premium price at launch."}'::jsonb),
('2-4-3-pricing-methods:mcq:8e38d193', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'mcq', 'mcq', 1, '{"question": "What is the primary danger of using Promotional Pricing too often?", "options": ["Customers may get used to the cheap prices and refuse to buy at full price.", "Competitors will immediately go bankrupt.", "The business will automatically gain a 100% market share.", "The cost of manufacturing the product will increase."]}'::jsonb, '{"answer": 0, "explain": "Correct answer: A. Frequent sales train customers to simply wait for the next sale rather than ever paying the full retail price, damaging long-term revenue."}'::jsonb),
('2-4-3-pricing-methods:mcq:fd4d7b2c', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'mcq', 'mcq', 1, '{"question": "Which pricing strategy is most likely to help a business recover high Research and Development (R&D) costs quickly?", "options": ["Penetration Pricing", "Price Skimming", "Loss Leader", "Competitor Pricing"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Price skimming generates high revenue margins immediately upon launch, which is crucial for tech or medical companies trying to pay back massive R&D investments."}'::jsonb),
('2-4-3-pricing-methods:mcq:f6e96419', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'mcq', 'mcq', 1, '{"question": "A new coach operator introduces a long-distance service. They charge £1 for tickets for the first month to establish the business. This is:", "options": ["Promotional pricing", "Price skimming", "Cost-plus pricing", "Premium pricing"]}'::jsonb, '{"answer": 0, "explain": "Correct answer: A. (Note: It also has elements of penetration, but OCR mark schemes heavily accept Promotional Pricing for short-term massive discounts used to help a new service become established)."}'::jsonb),
('2-4-3-pricing-methods:tf:f851810e', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'tf', 'tf', 1, '{"question": "Cost-plus pricing guarantees that a business will always make an overall profit for the year."}'::jsonb, '{"answer": false, "explain": "FALSE. While it guarantees a profit margin on *each item sold*, the business will still make an overall loss if they do not sell enough items to cover their fixed costs."}'::jsonb),
('2-4-3-pricing-methods:tf:46a3a661', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'tf', 'tf', 1, '{"question": "Penetration pricing is a strategy that a business should use permanently."}'::jsonb, '{"answer": false, "explain": "FALSE. Penetration pricing should only last for a short period of time. Once the business has established market share, it must raise prices, otherwise it will suffer low profitability long-term."}'::jsonb),
('2-4-3-pricing-methods:tf:af16be0b', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'tf', 'tf', 1, '{"question": "Price skimming is most effective when a business introduces a highly innovative, technological product with no direct rivals."}'::jsonb, '{"answer": true, "explain": "TRUE. Skimming works best when early adopters are desperate for the newest tech and are willing to pay a premium before competitors have time to copy the product."}'::jsonb),
('2-4-3-pricing-methods:tf:9f31a72b', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'tf', 'tf', 1, '{"question": "A disadvantage of competitor pricing is that the business has to spend money constantly researching what its rivals are charging."}'::jsonb, '{"answer": true, "explain": "TRUE. Competitor pricing requires constant monitoring of rival prices, which increases administrative costs."}'::jsonb),
('2-4-3-pricing-methods:tf:ba9e06a9', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'tf', 'tf', 1, '{"question": "A loss leader is a product that is sold at exactly the price it costs to manufacture."}'::jsonb, '{"answer": false, "explain": "FALSE. A loss leader is sold *below* the cost to manufacture. The business deliberately takes a financial loss on that specific item to entice customers into the store."}'::jsonb),
('2-4-3-pricing-methods:tf:e375ed0d', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'tf', 'tf', 1, '{"question": "Using promotional pricing too often can damage a brand''s image for quality."}'::jsonb, '{"answer": true, "explain": "TRUE. If a brand is constantly ''on sale'', customers stop seeing it as a premium product and refuse to ever pay the full retail price."}'::jsonb),
('2-4-3-pricing-methods:tf:2ebcb963', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'tf', 'tf', 1, '{"question": "Cost-plus pricing takes competitor prices into account before setting the final price."}'::jsonb, '{"answer": false, "explain": "FALSE. One of the main disadvantages of cost-plus pricing is that it completely *ignores* external factors like competitor prices and what customers are willing to pay."}'::jsonb),
('2-4-3-pricing-methods:tf:533f734b', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'tf', 'tf', 1, '{"question": "Price skimming involves starting with a low price and gradually raising it."}'::jsonb, '{"answer": false, "explain": "FALSE. You are describing penetration pricing. Price skimming starts HIGH and drops LOW as the product ages."}'::jsonb),
('2-4-3-pricing-methods:tf:17353439', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'tf', 'tf', 1, '{"question": "If a business uses competitor pricing, it must find a non-price way to stand out (like better service or packaging)."}'::jsonb, '{"answer": true, "explain": "TRUE. Because they cannot compete by being cheaper, they must differentiate their product in other ways."}'::jsonb),
('2-4-3-pricing-methods:tf:bebfccfc', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'tf', 'tf', 1, '{"question": "Penetration pricing builds brand loyalty because customers are attracted to try the product due to the low price."}'::jsonb, '{"answer": true, "explain": "TRUE. The low introductory price reduces the risk for customers to try an unknown brand. If the product is good, they develop loyalty and continue buying it even when the price rises."}'::jsonb),
('2-4-3-pricing-methods:tf:01119c7d', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'tf', 'tf', 1, '{"question": "A major supermarket like Tesco doesn''t need to consider competitor pricing because it is so large."}'::jsonb, '{"answer": false, "explain": "FALSE. The ''Big Four'' supermarkets operate in a highly competitive market and constantly monitor each other''s prices, frequently offering price-matches to avoid losing customers."}'::jsonb),
('2-4-3-pricing-methods:tf:581764be', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'tf', 'tf', 1, '{"question": "Price is the only element of the marketing mix that directly generates revenue."}'::jsonb, '{"answer": true, "explain": "TRUE. Product, Place, and Promotion all involve spending money (costs). Price dictates the money coming into the business."}'::jsonb),
('2-4-3-pricing-methods:learn:753da832', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'learn', 'mcq', 1, '{"readingTitle": "The Importance of Price", "reading": "<p>A business must take great care when deciding what price to charge for a product or service. Price is the only part of the marketing mix that directly generates <strong>revenue</strong>.</p>\n      <p>Most consumers take notice of the price. If a business sets a price too high, sales will fall. If it sets a price too low, it will not make the profits needed for investment and to reward shareholders. The price must also be consistent with the other 3 Ps (Product, Place, Promotion) as it affects the consumer''s perception of the good or service.</p>\n      <p><strong>Main factors that influence pricing decisions:</strong></p>\n      <ul>\n      <li>Costs (a business must cover its costs to survive)</li>\n      <li>Competitors'' prices</li>\n      <li>The Product Life Cycle (prices change as products age)</li>\n      <li>Market Share objectives</li>\n      <li>Positioning and Brand Image</li>\n      </ul>", "question": "Which part of the marketing mix is the only one that directly generates revenue for a business?", "options": ["Price", "Product", "Place", "Promotion"]}'::jsonb, '{"answer": 0, "explain": "Price is the only element of the 4Ps that directly brings money into the business; Product, Place and Promotion all involve costs."}'::jsonb),
('2-4-3-pricing-methods:learn:fe5baa30', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'learn', 'mcq', 1, '{"readingTitle": "Cost-Plus Pricing", "reading": "<p><strong>Cost-plus pricing</strong> is a method where the business looks at the total cost of manufacturing a product and then adds a percentage of profit (the ''mark-up'' or ''plus'' part) to arrive at the selling price.</p>\n      <div class=\"two-col\">\n      <div>\n      <div class=\"col-head\">✓ Advantages</div>\n      <div class=\"pro-item\">A profit is guaranteed on each item sold (providing enough items are sold).</div>\n      <div class=\"pro-item\">It is a relatively simple and easy way to set a price.</div>\n      <div class=\"pro-item\">Owners are in full control of the profit margin achieved.</div>\n      </div>\n      <div>\n      <div class=\"col-head\">✗ Disadvantages</div>\n      <div class=\"con-item\">Ignores external factors like competitor prices or customers'' willingness to pay.</div>\n      <div class=\"con-item\">If the mark-up is set too high, the price may be expensive compared to rivals, leading to lost sales.</div>\n      <div class=\"con-item\">If costs fluctuate frequently, the selling price may have to continually change.</div>\n      </div>\n      </div>", "question": "What is the main disadvantage of cost-plus pricing?", "options": ["It ignores competitor prices and what customers will pay", "It never guarantees a profit on items sold", "It cannot be calculated by small businesses", "It always results in lower profit margins than skimming"]}'::jsonb, '{"answer": 0, "explain": "Cost-plus pricing only considers internal costs plus a mark-up, so it ignores external factors such as competitors'' prices."}'::jsonb),
('2-4-3-pricing-methods:learn:9e592975', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'learn', 'mcq', 1, '{"readingTitle": "Competitor Pricing", "reading": "<p><strong>Competitor pricing</strong> (or competitive pricing) is used when there is a lot of competition selling the same or similar products. A business will look at what other competitors charge and charge the same (or very slightly less).</p>\n      <div class=\"two-col\">\n      <div>\n      <div class=\"col-head\">✓ Advantages</div>\n      <div class=\"pro-item\">Selling prices are in line with rivals, so it should attract customers and prevent them from switching brands.</div>\n      <div class=\"pro-item\">Helps a business survive in a highly crowded and established market.</div>\n      </div>\n      <div>\n      <div class=\"col-head\">✗ Disadvantages</div>\n      <div class=\"con-item\">Because price is the same as rivals, the business must find other (often expensive) ways to attract customers, like better customer service or more promotion.</div>\n      <div class=\"con-item\">The business must constantly research competitors'' prices, which increases administrative costs.</div>\n      </div>\n      </div>", "question": "A major disadvantage of competitor pricing is that a business...", "options": ["must find other costly ways to attract customers", "can no longer make any profit on its products", "must always price below all rivals", "will automatically dominate the market"]}'::jsonb, '{"answer": 0, "explain": "Because the price matches rivals, the business must compete on non-price factors like customer service or promotion, as the card''s disadvantages note."}'::jsonb),
('2-4-3-pricing-methods:learn:3d31f9f9', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'learn', 'mcq', 1, '{"readingTitle": "Penetration Pricing", "reading": "<p><strong>Penetration pricing</strong> is used when a business is new to a crowded market. They price their products <em>below</em> that of competitors to ''penetrate'' or break into the market and tempt consumers away from established brands. Once established, the price is raised. It is a short-term strategy.</p>\n      <div class=\"two-col\">\n      <div>\n      <div class=\"col-head\">✓ Advantages</div>\n      <div class=\"pro-item\">Cash flow and market share improve quickly as sales increase rapidly.</div>\n      <div class=\"pro-item\">Can lead to loyal customers who trial the product because of the low price and stick with it.</div>\n      <div class=\"pro-item\">Helps develop long-term profitability through higher market share.</div>\n      </div>\n      <div>\n      <div class=\"col-head\">✗ Disadvantages</div>\n      <div class=\"con-item\">In the short term, it is likely to result in lower profits (or even a loss) compared to if prices were higher.</div>\n      <div class=\"con-item\">It can be difficult to raise the selling price in the future without upsetting customers.</div>\n      </div>\n      </div>", "question": "Penetration pricing involves setting a price that is...", "options": ["below rivals to enter a crowded market, then raised", "above competitors to signal premium quality", "identical to competitors to avoid losing customers", "below cost permanently to eliminate all rivals"]}'::jsonb, '{"answer": 0, "explain": "Penetration pricing means pricing below rivals to ''penetrate'' a crowded market, with the price raised once the business is established."}'::jsonb),
('2-4-3-pricing-methods:learn:da82dafa', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'learn', 'mcq', 1, '{"readingTitle": "Price Skimming", "reading": "<p><strong>Price skimming</strong> (sometimes called ''creaming'') is used when a business introduces a new, unique, or highly technical product that is clearly superior to competitors. The business sets a very <em>high</em> price initially because early adopters are willing to pay a premium. The price drops later as competitors enter the market.</p>\n      <div class=\"two-col\">\n      <div>\n      <div class=\"col-head\">✓ Advantages</div>\n      <div class=\"pro-item\">Generates higher profits and revenues straight away, helping to quickly recover high Research & Development (R&D) costs.</div>\n      <div class=\"pro-item\">Gives the product a perceived brand image of high quality and exclusivity.</div>\n      </div>\n      <div>\n      <div class=\"col-head\">✗ Disadvantages</div>\n      <div class=\"con-item\">Cannot last long as the high profits will quickly attract competitors to create rival products.</div>\n      <div class=\"con-item\">Sales volume is slower because the product is expensive and many customers cannot afford it.</div>\n      </div>\n      </div>", "question": "Price skimming is most suitable for a business that has...", "options": ["a new, highly technical product facing no rivals yet", "an old product it needs to clear from stock", "identical products to lots of competitors", "a product aimed at very price-sensitive customers"]}'::jsonb, '{"answer": 0, "explain": "The card explains skimming is used when a business introduces a new, unique or highly technical product clearly superior to competitors."}'::jsonb),
('2-4-3-pricing-methods:learn:36feabf3', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'learn', 'mcq', 1, '{"readingTitle": "Promotional Pricing & Loss Leaders", "reading": "<p><strong>Promotional pricing</strong> is a reduction in price used for a short period to attract customers, boost falling sales, or get rid of old stock (e.g., in a sale).</p>\n      <p>A specific type of promotional pricing is a <strong>Loss Leader</strong>, where a product is deliberately sold at a price below its cost to make.</p>\n      <div class=\"two-col\">\n      <div>\n      <div class=\"col-head\">✓ Advantages</div>\n      <div class=\"pro-item\">Attracts footfall into a shop or visitors to a website.</div>\n      <div class=\"pro-item\">Customers who come for the cheap promotional item will hopefully buy other, full-priced, highly profitable products while they are there.</div>\n      <div class=\"pro-item\">Clears out old inventory to make room for new product lines.</div>\n      </div>\n      <div>\n      <div class=\"col-head\">✗ Disadvantages</div>\n      <div class=\"con-item\">If customers <em>only</em> buy the loss leader item, the business will make a financial loss.</div>\n      <div class=\"con-item\">Customers may get used to the cheap prices and refuse to buy the product when it returns to full price.</div>\n      <div class=\"con-item\">Too many sales can damage the brand''s reputation and premium image.</div>\n      </div>\n      </div>", "question": "What defines a ''loss leader''?", "options": ["A product sold below cost to draw customers into the shop", "A product sold at exactly its cost price to break even", "Any product included in a seasonal sale", "The best-selling product in a shop"]}'::jsonb, '{"answer": 0, "explain": "The card defines a loss leader as a product deliberately sold at a price below its cost to make, hoping customers buy other profitable items too."}'::jsonb),
('2-4-3-pricing-methods:misc:9964dd4c', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students confuse Penetration Pricing and Price Skimming.</p><p><strong>✅ The correct idea:</strong> PENETRATION = Start LOW to break into a market, then raise later. SKIMMING = Start HIGH to maximise profit on a new invention, then drop later as it ages.</p>", "question": "Which correctly distinguishes penetration pricing from price skimming?", "options": ["Penetration starts LOW; skimming starts HIGH on new items", "Penetration starts HIGH to maximise profit; skimming starts LOW to break into a market", "Both strategies start high and lower the price over time", "Both strategies start low and raise the price over time"]}'::jsonb, '{"answer": 0, "explain": "As the card clarifies, PENETRATION starts LOW to break in, while SKIMMING starts HIGH on a new invention and drops later."}'::jsonb),
('2-4-3-pricing-methods:misc:6525a65d', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students think Price Skimming means dropping the price to look like a bargain.</p><p><strong>✅ The correct idea:</strong> Examiners note this is a massive misconception. The value of skimming is NOT to drop the price later to look like a bargain. The value is charging a massive premium AT THE START to maximize financial returns from customers who want to be the first to own a superior product.</p>", "question": "According to the exam-note correction, what is the real value of price skimming?", "options": ["Charging a premium at the start to maximise early returns", "Dropping the price immediately to make it look like a bargain", "Matching competitor prices from day one", "Selling below cost to build a customer base quickly"]}'::jsonb, '{"answer": 0, "explain": "The card corrects the misconception: skimming''s value comes from charging a high price AT THE START, not from dropping it later to look cheap."}'::jsonb),
('2-4-3-pricing-methods:misc:11c703c3', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students think Cost-Plus pricing always results in high prices, making it unpopular.</p><p><strong>✅ The correct idea:</strong> Cost-plus only results in high prices if the business demands a massive percentage mark-up. Its actual flaw is that it ignores the market—it could accidentally set a price much lower than customers are willing to pay, or slightly higher than a rival.</p>", "question": "What is the real flaw of cost-plus pricing, as opposed to the misconception that it ''always results in high prices''?", "options": ["It ignores the market, risking too low a price", "It is illegal to use in competitive markets", "It guarantees a financial loss on every sale", "It cannot be used by manufacturing businesses"]}'::jsonb, '{"answer": 0, "explain": "The card explains cost-plus only leads to high prices with a large mark-up; its actual flaw is ignoring the market and rival prices entirely."}'::jsonb),
('2-4-3-pricing-methods:misc:d95b4c12', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> For ''analyse'' questions, students write impacts on the customer instead of the business.</p><p><strong>✅ The correct idea:</strong> If the question says ''Analyse one advantage to Shinz Ltd'', you must state how the pricing method impacts the BUSINESS (e.g. increased revenue, higher profit margin, improved cash flow). Saying ''the customer saves money'' scores zero for analysis.</p>", "question": "In an ''Analyse one advantage to [Business]'' pricing question, what must the analysis point focus on?", "options": ["The impact on the business, e.g. more revenue", "The impact on the customer, e.g. money saved", "The impact on the government", "The impact on the environment"]}'::jsonb, '{"answer": 0, "explain": "The card warns that stating ''the customer saves money'' scores zero; the analysis must show impact on the BUSINESS, such as revenue or cash flow."}'::jsonb),
('2-4-3-pricing-methods:tips:6c11276c', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'tips', 'mcq', 1, '{"readingTitle": "Analyse (3 marks) — Analysing a Pricing Method", "reading": "<p>Structure: Understanding of the method (1) &rarr; Application to the business (1) &rarr; Business-facing impact (1).</p>\n      <p><strong>Example (Cost-plus for a Salon):</strong> \"Cost-plus pricing ensures that the price always exceeds the costs of the business (U). By adding a mark-up to the wages of the new employees (APP), the salon guarantees that a profit is made on every haircut, avoiding a financial loss (AN).\"</p>\n      <p><strong>Warning:</strong> Do NOT explain *what* the method is (e.g. \"Cost-plus is when you add profit to costs\"). You must state a specific <em>advantage</em> or <em>disadvantage</em> to gain the first mark.</p>", "question": "In a 3-mark ''Analyse'' pricing question, what must you avoid doing if you want to gain the first mark?", "options": ["Just explaining the method, without an advantage or flaw", "Applying your answer to the case study business", "Stating a specific advantage or disadvantage of the method", "Concluding with a financial impact on the business"]}'::jsonb, '{"answer": 0, "explain": "The tip warns not to just explain what the method is (e.g. ''cost-plus is when...'') — you must state a specific advantage or disadvantage to gain the first mark."}'::jsonb),
('2-4-3-pricing-methods:tips:9a066d92', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'tips', 'mcq', 1, '{"readingTitle": "Evaluate (7 marks) — Evaluating the Importance of Price", "reading": "<p>If asked to evaluate the importance of price (e.g., Currys case study), you must weigh price against other factors.</p>\n      <p><strong>Yes, it is important:</strong> In markets like technology, products are identical (a Samsung TV is the same everywhere). Consumers use the internet to easily compare prices. Without competitive pricing, Currys will lose sales.</p>\n      <p><strong>No, other things matter:</strong> Quality of customer service (technical advice), the brand reputation, or the convenience of the store location might be more important to certain customers than saving a few pounds.</p>", "question": "When evaluating the importance of price for a business like Currys, what should a strong answer do?", "options": ["Weigh price against service, reputation, or location", "Only discuss why price is the single most important factor and ignore other factors", "Ignore competitor prices entirely", "Focus solely on the cost of manufacturing the product"]}'::jsonb, '{"answer": 0, "explain": "The tip states you must weigh price''s importance against other factors like customer service and location, not treat price in isolation."}'::jsonb),
('2-4-3-pricing-methods:tips:3b01c6e9', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'tips', 'mcq', 1, '{"readingTitle": "Recommend (3 marks) — Recommending a Strategy", "reading": "<p>When asked to recommend between two strategies (e.g., Skimming vs Competitor pricing), your justification MUST be <strong>comparative</strong>.</p>\n      <p><strong>Bad:</strong> \"Shinz Ltd should use competitor pricing because it will attract customers.\" (No comparison made).</p>\n      <p><strong>Good:</strong> \"Shinz Ltd should use competitor pricing (1) to ensure potential customers do not go to the rival car wash 5 miles away, whereas skimming would push price-sensitive customers directly to that rival (+2).\"</p>", "question": "When recommending one pricing strategy over another, what must the justification be?", "options": ["Comparative — the chosen strategy beats the alternative", "A simple restatement of the definition of the strategy", "Focused only on the strategy you did not choose", "Based purely on which strategy is cheapest to implement"]}'::jsonb, '{"answer": 0, "explain": "The tip states the justification MUST be comparative, showing why the chosen strategy beats the alternative for that specific business, not just listing a standalone benefit."}'::jsonb),
('2-4-3-pricing-methods:fib:6a78ad6b', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'fib', 'fib', 2, '{"question": "When a business first introduces a new product, it may use _____ pricing if it wants to gain market share from _____.", "blankOptions": {"B1": ["profit", "service", "penetration", "revenue"], "B2": ["promotional", "skimming", "competitors", "lower"]}}'::jsonb, '{"blanks": {"B1": "penetration", "B2": "competitors"}}'::jsonb),
('2-4-3-pricing-methods:fib:8a40b3c6', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'fib', 'fib', 2, '{"question": "If a product is highly technical and much better than the competition, a business might use price _____ to make as much _____ as they can initially.", "blankOptions": {"B1": ["high", "design", "skimming", "loss"], "B2": ["competitor", "design", "profit", "cash flow"]}}'::jsonb, '{"blanks": {"B1": "skimming", "B2": "profit"}}'::jsonb),
('2-4-3-pricing-methods:fib:5c5abb64', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'fib', 'fib', 2, '{"question": "After time, when a product becomes older, a business might have to _____ the price to keep sales high. To get rid of old stock entirely, _____ pricing is used.", "blankOptions": {"B1": ["skimming", "loss", "lower", "cost-plus"], "B2": ["cash flow", "profitable", "promotional", "cost-plus"]}}'::jsonb, '{"blanks": {"B1": "lower", "B2": "promotional"}}'::jsonb),
('2-4-3-pricing-methods:fib:b35ceef7', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'fib', 'fib', 2, '{"question": "A major benefit of _____ pricing is that it is a relatively simple way to set a price and ensures a profit margin is _____ on every item sold.", "blankOptions": {"B1": ["market", "promotional", "competitor", "cost-plus"], "B2": ["lower", "market", "loss", "guaranteed"]}}'::jsonb, '{"blanks": {"B1": "cost-plus", "B2": "guaranteed"}}'::jsonb),
('2-4-3-pricing-methods:fib:37745e25', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'fib', 'fib', 2, '{"question": "A _____ leader is a product sold below the cost it takes to make. The hope is that customers will buy other, highly _____ items while in the shop.", "blankOptions": {"B1": ["market", "promotional", "loss", "penetration"], "B2": ["lower", "cash flow", "profit", "profitable"]}}'::jsonb, '{"blanks": {"B1": "loss", "B2": "profitable"}}'::jsonb),
('2-4-3-pricing-methods:fib:d7619767', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'fib', 'fib', 2, '{"question": "If a business uses _____ pricing, it must find other ways to attract customers besides price, such as better customer _____ or heavier advertising.", "blankOptions": {"B1": ["cash flow", "promotional", "competitor", "skimming"], "B2": ["cost-plus", "service", "skimming", "market"]}}'::jsonb, '{"blanks": {"B1": "competitor", "B2": "service"}}'::jsonb),
('2-4-3-pricing-methods:fib:ef746900', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'fib', 'fib', 2, '{"question": "Price is a critical decision because it directly affects _____. Setting the price too high means sales will fall, but setting it too low damages _____.", "blankOptions": {"B1": ["profit", "revenue", "guaranteed", "design"], "B2": ["high", "cash flow", "guaranteed", "loss"]}}'::jsonb, '{"blanks": {"B1": "revenue", "B2": "cash flow"}}'::jsonb),
('2-4-3-pricing-methods:match:cc8ad865', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Penetration Pricing”?", "options": ["The costs of manufacturing the product plus the profit the business wants to make dictates the selling price.", "A short-term reduction in the price to attract customers, boost sales, or get rid of old stock.", "When a business is new to a crowded market, they price their products below competitors to gain market share.", "When a business has something new and unique, it sets a very high price until competition enters the market."]}'::jsonb, '{"answer": 2, "explain": "“Penetration Pricing” means: When a business is new to a crowded market, they price their products below competitors to gain market share."}'::jsonb),
('2-4-3-pricing-methods:match:bf0a80dc', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Cost-plus Pricing”?", "options": ["A short-term reduction in the price to attract customers, boost sales, or get rid of old stock.", "When a business has something new and unique, it sets a very high price until competition enters the market.", "When there is a lot of competition, a business looks at what rivals charge and charges the exact same.", "The costs of manufacturing the product plus the profit the business wants to make dictates the selling price."]}'::jsonb, '{"answer": 3, "explain": "“Cost-plus Pricing” means: The costs of manufacturing the product plus the profit the business wants to make dictates the selling price."}'::jsonb),
('2-4-3-pricing-methods:match:a494ed9f', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Promotional Pricing”?", "options": ["When a business has something new and unique, it sets a very high price until competition enters the market.", "A short-term reduction in the price to attract customers, boost sales, or get rid of old stock.", "When there is a lot of competition, a business looks at what rivals charge and charges the exact same.", "A product priced below its cost price to attract customers into the store, hoping they buy other profitable items."]}'::jsonb, '{"answer": 1, "explain": "“Promotional Pricing” means: A short-term reduction in the price to attract customers, boost sales, or get rid of old stock."}'::jsonb),
('2-4-3-pricing-methods:match:7682b4a5', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Price Skimming”?", "options": ["When there is a lot of competition, a business looks at what rivals charge and charges the exact same.", "A product priced below its cost price to attract customers into the store, hoping they buy other profitable items.", "The money coming into the business from selling goods; Price is the only part of the mix that directly generates this.", "When a business has something new and unique, it sets a very high price until competition enters the market."]}'::jsonb, '{"answer": 3, "explain": "“Price Skimming” means: When a business has something new and unique, it sets a very high price until competition enters the market."}'::jsonb),
('2-4-3-pricing-methods:match:25275ea0', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Competitor Pricing”?", "options": ["A product priced below its cost price to attract customers into the store, hoping they buy other profitable items.", "The money coming into the business from selling goods; Price is the only part of the mix that directly generates this.", "The percentage of profit added to the total cost of a product when using cost-plus pricing.", "When there is a lot of competition, a business looks at what rivals charge and charges the exact same."]}'::jsonb, '{"answer": 3, "explain": "“Competitor Pricing” means: When there is a lot of competition, a business looks at what rivals charge and charges the exact same."}'::jsonb),
('2-4-3-pricing-methods:match:10d82c0d', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Loss Leader”?", "options": ["The money coming into the business from selling goods; Price is the only part of the mix that directly generates this.", "The percentage of profit added to the total cost of a product when using cost-plus pricing.", "The proportion of total sales in a market held by one business; penetration pricing aims to increase this quickly.", "A product priced below its cost price to attract customers into the store, hoping they buy other profitable items."]}'::jsonb, '{"answer": 3, "explain": "“Loss Leader” means: A product priced below its cost price to attract customers into the store, hoping they buy other profitable items."}'::jsonb),
('2-4-3-pricing-methods:match:88a2bf7b', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Revenue”?", "options": ["The percentage of profit added to the total cost of a product when using cost-plus pricing.", "The proportion of total sales in a market held by one business; penetration pricing aims to increase this quickly.", "How a product is perceived by customers; skimming creates a premium perception, frequent promotions can damage it.", "The money coming into the business from selling goods; Price is the only part of the mix that directly generates this."]}'::jsonb, '{"answer": 3, "explain": "“Revenue” means: The money coming into the business from selling goods; Price is the only part of the mix that directly generates this."}'::jsonb),
('2-4-3-pricing-methods:match:75c34d04', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Mark-up”?", "options": ["The proportion of total sales in a market held by one business; penetration pricing aims to increase this quickly.", "How a product is perceived by customers; skimming creates a premium perception, frequent promotions can damage it.", "The percentage of profit added to the total cost of a product when using cost-plus pricing.", "Ignores external factors; the resulting price might be completely out of line with what customers are willing to pay."]}'::jsonb, '{"answer": 2, "explain": "“Mark-up” means: The percentage of profit added to the total cost of a product when using cost-plus pricing."}'::jsonb),
('2-4-3-pricing-methods:match:241e94ef', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Market Share”?", "options": ["The proportion of total sales in a market held by one business; penetration pricing aims to increase this quickly.", "How a product is perceived by customers; skimming creates a premium perception, frequent promotions can damage it.", "Ignores external factors; the resulting price might be completely out of line with what customers are willing to pay.", "Difficult to raise the price later without angering the loyal customers you just gained."]}'::jsonb, '{"answer": 0, "explain": "“Market Share” means: The proportion of total sales in a market held by one business; penetration pricing aims to increase this quickly."}'::jsonb),
('2-4-3-pricing-methods:match:36d9e44c', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Brand Image”?", "options": ["Ignores external factors; the resulting price might be completely out of line with what customers are willing to pay.", "Difficult to raise the price later without angering the loyal customers you just gained.", "When a business is new to a crowded market, they price their products below competitors to gain market share.", "How a product is perceived by customers; skimming creates a premium perception, frequent promotions can damage it."]}'::jsonb, '{"answer": 3, "explain": "“Brand Image” means: How a product is perceived by customers; skimming creates a premium perception, frequent promotions can damage it."}'::jsonb),
('2-4-3-pricing-methods:match:44c9c457', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Cost-plus Disadvantage”?", "options": ["Difficult to raise the price later without angering the loyal customers you just gained.", "When a business is new to a crowded market, they price their products below competitors to gain market share.", "Ignores external factors; the resulting price might be completely out of line with what customers are willing to pay.", "The costs of manufacturing the product plus the profit the business wants to make dictates the selling price."]}'::jsonb, '{"answer": 2, "explain": "“Cost-plus Disadvantage” means: Ignores external factors; the resulting price might be completely out of line with what customers are willing to pay."}'::jsonb),
('2-4-3-pricing-methods:match:caf90e69', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Penetration Disadvantage”?", "options": ["When a business is new to a crowded market, they price their products below competitors to gain market share.", "Difficult to raise the price later without angering the loyal customers you just gained.", "The costs of manufacturing the product plus the profit the business wants to make dictates the selling price.", "A short-term reduction in the price to attract customers, boost sales, or get rid of old stock."]}'::jsonb, '{"answer": 1, "explain": "“Penetration Disadvantage” means: Difficult to raise the price later without angering the loyal customers you just gained."}'::jsonb),
('2-4-4-promotion:exam:9f3f1bc3', '2-4-4-promotion', '2.4.4 Promotion', 'exam', 'mcq', 1, '{"num": "Q7", "question": "Which of the following is not a benefit to a business of using television advertising to promote its products?", "options": ["Celebrity endorsements can be used", "Financial risks are large", "Millions of potential customers can be reached", "Sound and moving images are very effective"], "hint": "A ''benefit'' is a good thing. Which of these is a BAD thing (a disadvantage)?", "starter": "Large financial risks are a..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme</h5><p><strong>Correct answer: B</strong></p><p>Large financial risks (due to the extremely high cost of TV advertising) are a major disadvantage, not a benefit.</p></div>", "modelAnswer": ""}'::jsonb),
('2-4-4-promotion:mcq:16c6cd38', '2-4-4-promotion', '2.4.4 Promotion', 'mcq', 'mcq', 1, '{"question": "Loss leaders are:", "options": ["leaders who always lose their way", "losses that a business makes when it sells leading products", "the losses a business makes every time it has a sale", "items that are sold at a low price to attract customers into a store"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: D. A loss leader is a point of sale promotion where a specific item is sold at a loss to entice shoppers into the store, hoping they buy other profitable items while there."}'::jsonb),
('2-4-4-promotion:mcq:f490c185', '2-4-4-promotion', '2.4.4 Promotion', 'mcq', 'mcq', 1, '{"question": "Which of the following is an example of social media advertising?", "options": ["A glossy advert in a fashion magazine", "Promoted posts on Facebook and Instagram", "A 30-second commercial on ITV", "A leaflet dropped through a letterbox"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Facebook, Instagram, Twitter/X, and TikTok are all social media platforms used for digital advertising."}'::jsonb),
('2-4-4-promotion:mcq:d8f8b0df', '2-4-4-promotion', '2.4.4 Promotion', 'mcq', 'mcq', 1, '{"question": "A local chip shop wanting to advertise its new menu would most likely use:", "options": ["a leaflet drop through letter boxes", "nationwide television advertising", "national radio advertising at peak times", "a glossy magazine advertising campaign"]}'::jsonb, '{"answer": 0, "explain": "Correct answer: A. A local chip shop only needs to reach people in its immediate geographical area. Nationwide TV or radio would be far too expensive and reach millions of people who live too far away to ever visit."}'::jsonb),
('2-4-4-promotion:mcq:4b025d30', '2-4-4-promotion', '2.4.4 Promotion', 'mcq', 'mcq', 1, '{"question": "A business wanting to let consumers try a small sample of its new cheese in a supermarket would be said to be using:", "options": ["loss leaders", "promotional advertising", "a promotion campaign", "point-of-sale promotion"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: D. Free samples given in the store where the product is sold are a form of Point of Sale promotion, designed to encourage an immediate purchase."}'::jsonb),
('2-4-4-promotion:mcq:65c7bd54', '2-4-4-promotion', '2.4.4 Promotion', 'mcq', 'mcq', 1, '{"question": "Which of the following is a benefit to a business of advertising on local radio?", "options": ["Detailed financial information can be included", "Can target a specific geographical area", "Free samples can be given out with the advertisement", "The product can be seen and demonstrated visually"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Local radio broadcasts to a specific town or county, allowing local businesses to target a specific geographical area very cost-effectively. Options A, C, and D are impossible on radio."}'::jsonb),
('2-4-4-promotion:mcq:b2f976ec', '2-4-4-promotion', '2.4.4 Promotion', 'mcq', 'mcq', 1, '{"question": "What is a major disadvantage to a business of using social media to promote its products?", "options": ["It is the most expensive form of advertising", "It can only reach people in a local town", "Customers can easily skip or ignore the adverts", "It is completely unregulated by law"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. While social media is cheap and highly targeted, users often scroll past or use ad-blockers, making it easy for the promotion to be ignored."}'::jsonb),
('2-4-4-promotion:mcq:0cb709f3', '2-4-4-promotion', '2.4.4 Promotion', 'mcq', 'mcq', 1, '{"question": "Sainsbury''s uses television to advertise its products. What is an advantage of this?", "options": ["It allows them to give out free samples to viewers", "It is the cheapest method of advertising available", "It uses high-impact audio and visuals to reach millions of mass-market consumers", "It guarantees that every viewer will visit the store"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. TV is very expensive, but it offers unparalleled reach (millions of viewers) and the ability to combine moving images, colour, and sound to demonstrate products."}'::jsonb),
('2-4-4-promotion:mcq:f71f4f8c', '2-4-4-promotion', '2.4.4 Promotion', 'mcq', 'mcq', 1, '{"question": "Which point of sale promotion involves reducing prices specifically to clear out old stock?", "options": ["Loss leaders", "Competitions", "Price reductions (Sales)", "Free samples"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. Price reductions (like January sales) are heavily used by clothing retailers to get rid of last season''s stock to make room for new items."}'::jsonb),
('2-4-4-promotion:mcq:ce0c0a17', '2-4-4-promotion', '2.4.4 Promotion', 'mcq', 'mcq', 1, '{"question": "Walkers Crisps runs a prize competition on the back of its Quavers packaging. What is the main business advantage of this?", "options": ["It targets people who have never eaten crisps before", "It guarantees the crisps taste better", "It reduces the cost of manufacturing the crisps", "It encourages existing customers to make large or repeat purchases for extra entries"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: D. Competitions on packaging encourage people who already buy the product to buy it *more often* in the hopes of winning the prize, driving up sales volume."}'::jsonb),
('2-4-4-promotion:mcq:58728e15', '2-4-4-promotion', '2.4.4 Promotion', 'mcq', 'mcq', 1, '{"question": "A company that sells highly specialised, expensive diving equipment wants to advertise. Which media is most appropriate?", "options": ["National television during a soap opera", "A local newspaper", "A specialist scuba-diving and watersports magazine", "A loss leader promotion in a supermarket"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. Specialist magazines allow a business to target a very specific, niche audience directly, meaning they don''t waste money advertising to the general public who do not dive."}'::jsonb),
('2-4-4-promotion:mcq:65372627', '2-4-4-promotion', '2.4.4 Promotion', 'mcq', 'mcq', 1, '{"question": "Boohoo.com targets 16-24 year olds who are fashion conscious. Which advertising media is best for this target market?", "options": ["National radio", "Social media (Instagram/TikTok)", "Local newspapers", "Television soap operas"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. 16-24 year olds are heavy users of social media. Advertising there allows Boohoo to target their core demographic accurately and link them directly to their online store."}'::jsonb),
('2-4-4-promotion:mcq:34454e28', '2-4-4-promotion', '2.4.4 Promotion', 'mcq', 'mcq', 1, '{"question": "Which of the following is NOT a key aim of promotion?", "options": ["To inform customers about a new product", "To create or change the brand''s image", "To reduce the costs of manufacturing", "To maintain or increase sales"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. Promotion is a marketing function and involves spending money to increase sales or awareness. It has absolutely nothing to do with reducing the operational costs of manufacturing a product."}'::jsonb),
('2-4-4-promotion:tf:5fcdb119', '2-4-4-promotion', '2.4.4 Promotion', 'tf', 'tf', 1, '{"question": "A loss leader is meant to make a loss to keep the business in the lead."}'::jsonb, '{"answer": false, "explain": "FALSE. A loss leader is a product sold at a financial loss to attract customers into a store, in the hope they will buy other, fully-priced profitable items while there."}'::jsonb),
('2-4-4-promotion:tf:ca23cf19', '2-4-4-promotion', '2.4.4 Promotion', 'tf', 'tf', 1, '{"question": "Competitions are only used by supermarkets to promote the food they sell."}'::jsonb, '{"answer": false, "explain": "FALSE. Competitions can be used by any business (e.g., car dealerships, clothing brands, cereal manufacturers) to encourage purchases."}'::jsonb),
('2-4-4-promotion:tf:dac567fa', '2-4-4-promotion', '2.4.4 Promotion', 'tf', 'tf', 1, '{"question": "Price reductions are often seen in shops in January."}'::jsonb, '{"answer": true, "explain": "TRUE. January sales are a classic example of using price reductions as a point of sale promotion to clear out old winter stock."}'::jsonb),
('2-4-4-promotion:tf:ccd54b2e', '2-4-4-promotion', '2.4.4 Promotion', 'tf', 'tf', 1, '{"question": "Free samples are often seen in products such as cosmetics or food."}'::jsonb, '{"answer": true, "explain": "TRUE. Free samples persuade customers to try a product risk-free, which is highly effective for items where scent or taste is the primary selling point."}'::jsonb),
('2-4-4-promotion:tf:f6caa625', '2-4-4-promotion', '2.4.4 Promotion', 'tf', 'tf', 1, '{"question": "Supermarkets use loss leaders to encourage shoppers to visit their stores."}'::jsonb, '{"answer": true, "explain": "TRUE. Supermarkets might sell bread or milk at a loss, knowing that a customer will likely also buy meat, vegetables, and treats that have a high profit margin."}'::jsonb),
('2-4-4-promotion:tf:56c909fd', '2-4-4-promotion', '2.4.4 Promotion', 'tf', 'tf', 1, '{"question": "Promotion is mainly concerned with making sure that old stock is sold at the best possible price."}'::jsonb, '{"answer": false, "explain": "FALSE. While price reductions clear old stock, the main aims of promotion are much wider: informing customers of new products, increasing sales, and building brand image."}'::jsonb),
('2-4-4-promotion:tf:4f1137ea', '2-4-4-promotion', '2.4.4 Promotion', 'tf', 'tf', 1, '{"question": "Not all businesses use promotion to help them sell products and services."}'::jsonb, '{"answer": false, "explain": "FALSE. Virtually every business must use some form of promotion (even if it''s just a shop sign or word of mouth) to make customers aware they exist."}'::jsonb),
('2-4-4-promotion:tf:5d9bb027', '2-4-4-promotion', '2.4.4 Promotion', 'tf', 'tf', 1, '{"question": "Local radio is an excellent way for a national supermarket chain to reach the whole UK."}'::jsonb, '{"answer": false, "explain": "FALSE. Local radio only reaches a small geographical area. A national supermarket would use national television or national newspapers to reach the whole UK."}'::jsonb),
('2-4-4-promotion:tf:f17a1fd9', '2-4-4-promotion', '2.4.4 Promotion', 'tf', 'tf', 1, '{"question": "Social media allows a business to target its advertising very precisely based on user age and interests."}'::jsonb, '{"answer": true, "explain": "TRUE. Platforms like Instagram and Facebook collect massive amounts of user data, allowing businesses (like Boohoo) to target exact demographics like 16-24 year olds."}'::jsonb),
('2-4-4-promotion:tf:65abacbb', '2-4-4-promotion', '2.4.4 Promotion', 'tf', 'tf', 1, '{"question": "One advantage of print media (like magazines) is that they can include physical scent samples or glossy images."}'::jsonb, '{"answer": true, "explain": "TRUE. Glossy magazines are perfect for high-end fashion and perfume brands because they support a premium image and can even include physical ''rub and sniff'' samples."}'::jsonb),
('2-4-4-promotion:tf:0d60ff79', '2-4-4-promotion', '2.4.4 Promotion', 'tf', 'tf', 1, '{"question": "A major disadvantage of television advertising is that it lacks visual impact."}'::jsonb, '{"answer": false, "explain": "FALSE. Television has massive visual and audio impact. It is *radio* that lacks visual impact."}'::jsonb),
('2-4-4-promotion:tf:75edb2d8', '2-4-4-promotion', '2.4.4 Promotion', 'tf', 'tf', 1, '{"question": "A business should choose its advertising media based on where its target market is most likely to see it."}'::jsonb, '{"answer": true, "explain": "TRUE. A business must match its media to its market. You wouldn''t advertise skateboards in a retirement magazine, or luxury cars on a budget leaflet."}'::jsonb),
('2-4-4-promotion:tf:bfea2b67', '2-4-4-promotion', '2.4.4 Promotion', 'tf', 'tf', 1, '{"question": "Social media advertising is generally much more expensive than national television advertising."}'::jsonb, '{"answer": false, "explain": "FALSE. National TV is usually the most expensive form of advertising, costing millions. Social media can be done on a much smaller, highly targeted budget."}'::jsonb),
('2-4-4-promotion:tf:a3bc9164', '2-4-4-promotion', '2.4.4 Promotion', 'tf', 'tf', 1, '{"question": "Giving away 30% extra free in a bottle of cola is an example of point of sale promotion."}'::jsonb, '{"answer": true, "explain": "TRUE. This acts like a free sample/bonus that tempts the customer to choose that specific bottle off the shelf over a rival brand."}'::jsonb),
('2-4-4-promotion:learn:a6e68168', '2-4-4-promotion', '2.4.4 Promotion', 'learn', 'mcq', 1, '{"readingTitle": "Introduction to Promotion", "reading": "<p><strong>Promotion</strong> is about informing customers about what is for sale and persuading them to buy. When a business has a good product, or is offering a good price, it needs to inform its customers. This makes promotion highly interconnected with the other ''Ps'' of the marketing mix.</p>\n      <p><strong>There are four key aims of promotion:</strong></p>\n      <ol>\n      <li>To inform customers about a product or service (especially when it is new or has changed).</li>\n      <li>To keep a business ahead of its competitors.</li>\n      <li>To create or change the image of a business, its products, and services.</li>\n      <li>To maintain or increase sales.</li>\n      </ol>\n      <p>Promotion is generally divided into two main areas: <strong>Point of Sale Promotion</strong> and <strong>Advertising Media</strong>.</p>", "question": "What is the main purpose of promotion within the marketing mix?", "options": ["To reduce the cost of manufacturing a product", "To inform and persuade customers to buy a product", "To set the price of a product based on demand", "To decide where a product will be distributed"]}'::jsonb, '{"answer": 1, "explain": "Promotion is defined as informing customers about what is for sale and persuading them to buy it, making it distinct from the other Ps of the marketing mix."}'::jsonb),
('2-4-4-promotion:learn:82ad7b46', '2-4-4-promotion', '2.4.4 Promotion', 'learn', 'mcq', 1, '{"readingTitle": "Point of Sale Promotion", "reading": "<p><strong>Point of Sale promotions</strong> are specific offers available when purchasing a product. They are designed to tempt customers to make an immediate purchase.</p>\n      <ul>\n      <li><strong>Price Reductions (Sales):</strong> Used mainly to sell off old stock (e.g., winter clothes as spring approaches). The disadvantage is that the business makes less profit per item than if sold at the original price.</li>\n      <li><strong>Competitions:</strong> A person who buys a product is entered into a competition (e.g., to win a free holiday). This encourages large, multiple, or repeat purchases as customers buy more to gain extra entries.</li>\n      <li><strong>Free Samples:</strong> Often seen with products like cosmetics or food/soft drinks. Giving a 30% extra free bottle or a free tasting sample persuades consumers to try a product they haven''t had before.</li>\n      <li><strong>Loss Leaders:</strong> Items that are deliberately sold at a loss to attract customers into a store. The hope is that once the customer is inside, they will be tempted to buy other, highly profitable products at the same time.</li>\n      </ul>", "question": "What is the defining feature of a Point of Sale promotion?", "options": ["It broadcasts a brand message to the wider public over several weeks", "It only applies to products sold online", "It offers an incentive at the point of purchase to trigger a sale", "It is used exclusively to build long-term brand image"]}'::jsonb, '{"answer": 2, "explain": "Point of Sale promotions (like price reductions, competitions, free samples and loss leaders) are specific offers available when purchasing, designed to tempt an immediate purchase."}'::jsonb),
('2-4-4-promotion:learn:b54b1729', '2-4-4-promotion', '2.4.4 Promotion', 'learn', 'mcq', 1, '{"readingTitle": "Advertising Media", "reading": "<p><strong>Advertising media</strong> are the various ways a company can communicate its message to the wider public to build brand awareness.</p>\n      <ul>\n      <li><strong>Social Media (Facebook, Instagram, Twitter/X):</strong> Excellent for targeting specific demographics (like 16-24 year olds). It is relatively cheap and has a global reach, but users can easily skip ads, and maintaining a social media presence requires constant monitoring.</li>\n      <li><strong>Television:</strong> Reaches millions of people and has high visual and audio impact. It is perfect for mass-market products (like supermarkets or insurance comparison sites). However, it is the most expensive form of advertising.</li>\n      <li><strong>Print Media (Newspapers & Magazines):</strong> Magazines are great for targeting specific groups (e.g., a high-end perfume in a glossy fashion magazine). National newspapers reach a wide audience, while local newspapers are perfect for small, local businesses.</li>\n      <li><strong>Radio:</strong> Local radio allows a business to target a specific geographical area cheaply. National radio reaches a wide audience. However, it lacks visual impact so products cannot be demonstrated.</li>\n      <li><strong>Websites:</strong> Businesses use their own sites or pay for banner ads on other popular sites. E-commerce platforms like ASOS or Boohoo rely heavily on digital advertising to drive traffic directly to their digital checkout.</li>\n      </ul>", "question": "Which advertising media offers high visual and audio impact and reaches millions of people, but is the most expensive option?", "options": ["Local radio", "Print media", "Social media", "Television"]}'::jsonb, '{"answer": 3, "explain": "Television reaches millions of people with high visual and audio impact, making it ideal for mass-market products, but it is described as the most expensive form of advertising."}'::jsonb),
('2-4-4-promotion:learn:aea50020', '2-4-4-promotion', '2.4.4 Promotion', 'learn', 'mcq', 1, '{"readingTitle": "Case Study: Mobile Phone Services", "reading": "<p><strong>Three, EE, Vodafone, O2</strong></p>\n      <p>Millions of people buy and use mobile phones. The main companies supplying the phones and services are in close competition. They are constantly updating the deals they offer (e.g., price, 5G coverage, data, Apple Music add-ons) hoping to persuade consumers to change to their service.</p>\n      <p>Without promotion, customers would be completely unaware of these deals. Mobile phone companies spend a massive amount of money on advertising to ensure all potential buyers know about their offers. Because the market is so saturated, each company has to aggressively match the promotion of the others to attract new customers and keep existing ones; otherwise, rivals will step in and steal their market share.</p>", "question": "Why do mobile network providers like EE and Vodafone spend heavily on promotion even though the market is already saturated?", "options": ["To reduce the manufacturing cost of handsets", "Because government regulation forces them to advertise their handsets", "To stop rivals stealing market share by keeping customers informed", "Because they have no real competitors to worry about"]}'::jsonb, '{"answer": 2, "explain": "In a saturated market, each company must aggressively match rivals'' promotion to attract and retain customers, otherwise competitors will step in and steal market share."}'::jsonb),
('2-4-4-promotion:learn:f6db8ee4', '2-4-4-promotion', '2.4.4 Promotion', 'learn', 'mcq', 1, '{"readingTitle": "Case Study: Go Compare & Compare the Market", "reading": "<p>Price comparison websites like <strong>Go Compare</strong> and <strong>Compare the Market</strong> use heavy Television advertising to promote their services. Their target market is essentially every household in the UK that needs car, home, or pet insurance.</p>\n      <p><strong>Evaluation: Should they concentrate on TV?</strong><br>\n      Yes, they should. They earn their money by providing links to different insurance companies; the more links clicked, the more money they earn. Because their target market is so broad (all UK households), no other advertising media can match the sheer volume and reach of TV. While radio or social media might be cheaper, it would not reach the same millions of potential mass-market consumers, allowing rivals to ''steal'' their customers and reduce their income.</p>", "question": "Why is television advertising judged to be the right choice for Go Compare and Compare the Market?", "options": ["TV is the cheapest media option available to them", "Their target market is every UK household, so TV gives the best reach", "TV only reaches people already searching online for insurance deals", "It allows them to target just one narrow age group precisely"]}'::jsonb, '{"answer": 1, "explain": "Because their target market is so broad (all UK households needing insurance), the evaluation concludes no other advertising media can match the sheer volume and reach of TV, even though it is expensive."}'::jsonb),
('2-4-4-promotion:learn:8e0dcc45', '2-4-4-promotion', '2.4.4 Promotion', 'learn', 'mcq', 1, '{"readingTitle": "Choosing the Right Promotion", "reading": "<p>Different situations require different promotional methods. A business must evaluate the <strong>Cost</strong> vs the <strong>Target Audience</strong>.</p>\n      <ul>\n      <li><strong>A local chip shop or cafe:</strong> Needs local advertising. A leaflet drop through local letterboxes or an ad on local radio is cost-effective and hits the exact geographic target. TV would be a massive waste of money.</li>\n      <li><strong>A famous perfume brand:</strong> Needs to maintain a premium brand image. Glossy photographs in high-end fashion magazines are ideal.</li>\n      <li><strong>A highly specialized tech product (e.g., advanced sat-nav):</strong> Should be advertised in specialist motoring or tech magazines to hit a niche target market directly.</li>\n      <li><strong>ASOS / Boohoo.com:</strong> Both target 16-24 year old fashion-conscious consumers. Social media (Instagram, TikTok) is the most effective way to reach this demographic, combining targeted ads with direct links to their e-commerce apps.</li>\n      </ul>", "question": "What two factors must a business weigh up most carefully when choosing the right promotional method for a situation?", "options": ["The size of the shop window display and the colour scheme", "The cost of the method and the nature of the target audience", "The age of the business owner and their personal taste", "The number of competitors within the same postcode"]}'::jsonb, '{"answer": 1, "explain": "The card states a business must evaluate the Cost versus the Target Audience, which is why a local café uses cheap local media while a mass-market brand may justify TV."}'::jsonb),
('2-4-4-promotion:misc:14ecbacc', '2-4-4-promotion', '2.4.4 Promotion', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students often confuse ''Point of Sale Promotion'' with ''Advertising Media''.</p><p><strong>✅ The correct idea:</strong> Point of Sale is the specific offer at the shop/checkout to force a quick sale (e.g. BOGOF, 50% off, free sample). Advertising Media is the channel used to broadcast a message to the wider world (e.g. TV, Radio, Social Media).</p>", "question": "How does Point of Sale Promotion differ from Advertising Media?", "options": ["They are the same thing; both terms just describe general advertising to the public", "Advertising Media only applies to online businesses", "Point of Sale is the checkout offer; Advertising Media is the wider broadcast channel", "Point of Sale is always more expensive than Advertising Media"]}'::jsonb, '{"answer": 2, "explain": "Point of Sale is the specific offer at the till/shop (e.g. BOGOF, free sample), whereas Advertising Media is the broadcast channel (e.g. TV, radio, social media) used to reach a wider audience."}'::jsonb),
('2-4-4-promotion:misc:73f62d71', '2-4-4-promotion', '2.4.4 Promotion', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students think ''Loss Leader'' just means the business is losing money generally.</p><p><strong>✅ The correct idea:</strong> A Loss Leader is a highly specific strategy: deliberately pricing ONE specific item below its cost to make, acting as bait to draw customers into the store so they buy OTHER profitable items.</p>", "question": "What does the term ''Loss Leader'' specifically mean?", "options": ["A business that is generally losing money overall", "Pricing one specific item below cost to draw customers into the store", "A manager who has lost control of the sales team", "A product that has been recalled by the manufacturer due to poor quality"]}'::jsonb, '{"answer": 1, "explain": "A Loss Leader is a specific strategy of pricing ONE item below cost as bait, not a general sign that the whole business is losing money."}'::jsonb),
('2-4-4-promotion:misc:2debd918', '2-4-4-promotion', '2.4.4 Promotion', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> When asked for an advantage of a specific media (e.g. TV), students give a generic advantage of promotion (e.g. ''it gets more customers'').</p><p><strong>✅ The correct idea:</strong> You must give an advantage UNIQUE to that media. For TV: ''It provides moving images and sound to demonstrate the product''. For Local Radio: ''It targets a specific geographical town cheaply''.</p>", "question": "When an exam question asks for an advantage of a named media such as TV, what must the answer include to score well?", "options": ["A generic advantage of promotion, such as ''it gets more customers''", "A feature unique to that media, such as TV''s moving images and sound", "A comparison to every other media type available", "Just the name of the media repeated back"]}'::jsonb, '{"answer": 1, "explain": "Marks require an advantage UNIQUE to the named media (e.g. TV shows moving images and sound; local radio targets a specific town cheaply), not a vague, generic benefit of promotion."}'::jsonb),
('2-4-4-promotion:misc:f22fac74', '2-4-4-promotion', '2.4.4 Promotion', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students suggest TV advertising for small, local businesses (like a single café).</p><p><strong>✅ The correct idea:</strong> TV advertising is massively expensive and reaches a national audience. It is completely inappropriate for a single local café. Always match the scale of the media to the scale of the business.</p>", "question": "Why would recommending TV advertising for a single local café be a poor exam answer?", "options": ["TV cannot legally be used to advertise a small, independent local business such as a café", "TV is very expensive and reaches a national audience, wasting money on distant people", "TV adverts cannot include images of food", "Local cafés are not allowed to advertise at all"]}'::jsonb, '{"answer": 1, "explain": "The scale of the media must match the scale of the business; TV is hugely expensive and reaches a national audience, which is inappropriate and wasteful for a single local café."}'::jsonb),
('2-4-4-promotion:tips:7e4f7d00', '2-4-4-promotion', '2.4.4 Promotion', 'tips', 'mcq', 1, '{"readingTitle": "State / Identify (1 mark) — Naming Advertising Media", "reading": "<p>If asked to state an advertising media, be specific. \"Internet\" is a bit vague — use \"Social media\" or \"Company Website\".</p>\n      <p><strong>Accepted Media:</strong> Television / Local or National Radio / Social Media / Print Media (Newspapers/Magazines) / Leaflets / Billboards.</p>", "question": "Why would writing ''the internet'' as an answer to ''state an advertising media'' likely lose the mark?", "options": ["The internet is not accepted as an advertising media answer at all", "It is too vague; a specific method like ''social media'' is needed", "Only television and radio are ever accepted as answers", "It should be written in full as ''World Wide Web''"]}'::jsonb, '{"answer": 1, "explain": "For a 1-mark ''state/identify'' question you must be specific — the tip warns that ''internet'' is too vague and examiners want a named method like ''social media'' or ''company website''."}'::jsonb),
('2-4-4-promotion:tips:36aafcc4', '2-4-4-promotion', '2.4.4 Promotion', 'tips', 'mcq', 1, '{"readingTitle": "Analyse (3 marks) — Analysing a Media Choice", "reading": "<p>Structure: Identify a feature of the media (U) &rarr; Apply to the business scenario (APP) &rarr; State the business impact (AN).</p>\n      <p><strong>Example (Sainsbury''s using TV):</strong> \"TV allows the use of moving images and sound to demonstrate products (U). Sainsbury''s can use this to visually show the high quality of its food ranges to middle-income earners (APP), which will increase brand awareness and boost total sales revenue (AN).\"</p>", "question": "What is the correct three-step structure for answering a 3-mark ''Analyse a media choice'' exam question?", "options": ["State the business''s turnover, then its profit, then its market share", "Identify a feature of the media, apply it to the scenario, then state the impact", "List every advertising media the business could use, in order of cost", "Give the business''s opinion, a counter-opinion, and then a final overall decision"]}'::jsonb, '{"answer": 1, "explain": "The tip sets out the structure as Understanding a feature of the media, Application to the business scenario, then Analysis of the business impact (U -> APP -> AN)."}'::jsonb),
('2-4-4-promotion:tips:61577bad', '2-4-4-promotion', '2.4.4 Promotion', 'tips', 'mcq', 1, '{"readingTitle": "Evaluate (7 marks) — Evaluating Promotional Methods", "reading": "<p>When asked to recommend or evaluate a promotional method (like the Boohoo social media question or Walkers Newspaper vs Competition question), you must weigh the <strong>Pros and Cons</strong>.</p>\n      <ul>\n      <li><strong>Cost:</strong> Is the business a small sole trader or a massive Plc? Can they afford TV?</li>\n      <li><strong>Target Market:</strong> Where does the target market look? (e.g., 16-24 year olds look at TikTok, not the local newspaper).</li>\n      <li><strong>Reach:</strong> Do they need national reach or just local town reach?</li>\n      </ul>\n      <p>Always justify your final decision using the specific context of the case study business.</p>", "question": "What must a 7-mark ''Evaluate'' answer on a promotional method include to score full marks?", "options": ["A list of every possible advertising media with no final decision", "Only the cheapest promotional method, with no discussion of the target market at all", "A weighing of pros and cons, plus a justified final decision using case study context", "A single sentence stating a preference without any reasoning"]}'::jsonb, '{"answer": 2, "explain": "Evaluate questions require weighing pros and cons such as cost, target market and reach, then justifying the final decision using the specific context of the case study business."}'::jsonb),
('2-4-4-promotion:fib:01f90d57', '2-4-4-promotion', '2.4.4 Promotion', 'fib', 'fib', 2, '{"question": "Promotion is about _____ customers about what is for sale and _____ them to buy.", "blankOptions": {"B1": ["stock", "skip", "social", "informing"], "B2": ["persuading", "magazines", "competition", "market"]}}'::jsonb, '{"blanks": {"B1": "informing", "B2": "persuading"}}'::jsonb),
('2-4-4-promotion:fib:b891f016', '2-4-4-promotion', '2.4.4 Promotion', 'fib', 'fib', 2, '{"question": "A _____ leader is a product deliberately sold at a _____ to attract customers into a store.", "blankOptions": {"B1": ["screen", "loss", "visual", "competitors"], "B2": ["loss", "samples", "informing", "visual"]}}'::jsonb, '{"blanks": {"B1": "loss", "B2": "loss"}}'::jsonb),
('2-4-4-promotion:fib:450d6f24', '2-4-4-promotion', '2.4.4 Promotion', 'fib', 'fib', 2, '{"question": "Point of _____ promotions include price reductions, competitions, and free _____.", "blankOptions": {"B1": ["sale", "competition", "households", "customers"], "B2": ["skip", "samples", "competitors", "persuading"]}}'::jsonb, '{"blanks": {"B1": "sale", "B2": "samples"}}'::jsonb)
